var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"무사히 목적지에 도착했다, 제군들!","JPN":"皆、着いたよ！","ENG":"We've safely arrived at the destination!","TWN":"我們安全到達目的地了，各位！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"여기가 모험의 종착지인 블루로즈 섬이야!","JPN":"ここが冒険の最終地点、ブルーローズ島だ！","ENG":"This is the last stop of the journey, Blue Rose Island!","TWN":"這裡就是冒險的終點，藍玫瑰島！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"전원 한 줄로 서서 질서 있게 입장하도록!","JPN":"全員ちゃんと一列に並んでね！","ENG":"Everyone, make a line and enter in an orderly manner!","TWN":"全員排成一列，依序入場！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"확인했습니다. 그럼 즐거운 시간 되세요!","JPN":"確認いたしました。それでは素敵な時間を！","ENG":"Confirmed. Have a great time!","TWN":"好的，已確認。祝你們玩得開心！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"휴우.","JPN":"ふう。","ENG":"Phew.","TWN":"呼。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 섬에 들어오는 데에도 입장권이 필요한 줄은 몰랐네요.","JPN":"まさか島への上陸にチケットが必要だとは思いませんでした。","ENG":"I didn't think we'd need tickets to enter the island.","TWN":"沒想到進島也需要入場券。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"기껏 여기까지 왔는데 문전박대 당했으면… 으으.","JPN":"ここまで来て、上陸もできず帰ることになっていたらと思うと……うう。","ENG":"I can't imagine what we would've done if we made it all the way here and got kicked out at the entrance.","TWN":"好不容易來到這裡，如果被拒之門外的話……呃呃。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그래도 다행입니다. 시그마의 지인 중에 티켓을 구할 수 있는 사람이 있어서.","JPN":"シグマのツテでチケットを購入できる方がいたのは、幸いだったね。","ENG":"It is a relief that Sigma's acquaintance could get us tickets.","TWN":"幸運的是西格瑪認識能搞到票的熟人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말로요. 유미나라는 분한테는 나중에 감사 인사라도 하자고요.","JPN":"はい。ヤナギ・ミナさんには改めてお礼をしましょう。","ENG":"For sure. Let's thank this \\"Yoo Mina\\" person later.","TWN":"嗯嗯。以後一定要好好謝謝這位劉米娜。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유피! 크레데레!","JPN":"ユピ！　クレデレ！","ENG":"Yuppie! Credere!","TWN":"悠菲！克蕾妲莉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님? 통화는 끝났나요?","JPN":"室長？　お電話はもう済んだのですか？","ENG":"Chief? Are you done with your phone call?","TWN":"室長？通話結束了嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으응. 그것 말인데.","JPN":"あ、うん。その話なんだけど……","ENG":"Yeah. About that.","TWN":"唔，關於那個……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"응? 보물에 대해 뭔가 짚이는 구석은 없냐고?","JPN":"え？　お宝についての私の予想？","ENG":"Hmm? Do I have any guesses about where the treasure is?","TWN":"嗯？我對寶藏有什麼頭緒嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"몰라. 애초에 나는 저번 탐험 이후로 아카데미에만 갇혀 있었다고.","JPN":"見当もつかないわよ。私は前回の探検以来、ずっとアカデミーに引き籠っていたんだから。","ENG":"Not really. I've been stuck in the Academy ever since that last expedition.","TWN":"不清楚。自從上次探險之後，我就一直被留在學院裡。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그것보다… 보물을 찾는 거라면 나를 데리고 가는 건 어때? 분명 다른 녀석들보다-","JPN":"それより、お宝を探しに行くなら私を連れていかない？　きっと他の連中より……","ENG":"If you're looking for treasure, you can always take me! I'm sure I'll be a lot more helpful than–","TWN":"比起這個……如果是找寶藏的話，帶上我怎麼樣？肯定比其他傢伙——"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"히익?!","JPN":"ひいっ……！","ENG":"Eek?!","TWN":"欸？!"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"죄송합니다, 시그마 양. 잠시 소란이 있었군요.","JPN":"申し訳ございません、シグマさん。お騒がせしました。","ENG":"My apologies, Sigma. There was a short disturbance.","TWN":"抱歉，西格瑪，剛剛有點小騷亂。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"복원해 주신 영상을 분석한 결과, 시그마 양의 말 대로 범인이 섬에 있다는 사실은 파악했습니다.","JPN":"復元していただいた映像を解析したところ、シグマさんのおっしゃる通り、犯人はこの島にいることがほぼ確定しました。","ENG":"Based on the analysis of the restored footage, we were able to glean that the criminal is indeed on the island, like you said.","TWN":"根據你恢復的影片進行分析後，我們確認了你所說的犯人確實在島上。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 범인이 전파공작에 능한지… 그 위치까지는 정확히 파악할 수가 없군요.","JPN":"ですが、犯人は電波工作に長けているらしく、位置の把握まではできていません。","ENG":"But this culprit must be skilled in electronic operations... because we could not locate the exact coordinates.","TWN":"但是，犯人同樣擅長反追蹤……我們還無法準確確定其位置。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"모처럼 부탁해 주셨는데 죄송합니다. 별다른 도움은 되지 못할 것 같군요.","JPN":"せっかく要請いただいたのに、あまりお役に立てずすみません。","ENG":"I apologize for not being of more help.","TWN":"難得你開口了，真是抱歉，我恐怕幫不上什麼忙。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아냐, 옌 언니. 티켓을 받은 것만으로도 충분한걸?","JPN":"イェンお姉ちゃん、気にしないで。チケットの件で助けてもらっただけでも十分だよ。","ENG":"Don't say that, Yen. It was more than enough that you got us the tickets.","TWN":"不，嫣杏姊姊。能拿到票就已經足夠了。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다른 사람도 아닌 미나 양의 부탁이니까요. 신경 쓰지 않으셔도 된답니다.","JPN":"いえいえ。ミナさんからの頼みとあれば、無下にはできませんので。","ENG":"Anything for Mina. Don't worry about that.","TWN":"又不是別人，是米娜親自開的口。你不用擔心。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스 양에게도 말해 놨으니, 혹여 알게 되는 것이 있다면 곧바로 연락드리죠.","JPN":"イディスさんにもお伝えしておいたので、もしも新しくわかったことがあればすぐにご連絡します。","ENG":"I also talked to Edith, so I will let you know if I hear anything.","TWN":"我已經告訴伊蒂絲了，如果有任何發現，會立刻聯絡你。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물의 위치는 다른 언니들도 잘 모르는 것 같아.","JPN":"お宝の在り処はお姉ちゃんたちも、よく知らないみたい。","ENG":"I don't think the others know the location of the treasure.","TWN":"寶藏的位置好像連其他姊姊們也不太清楚。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"나도 계속 연산 중이지만 정보가 부족해.","JPN":"私も演算は回し続けているけど、どうしても情報が足りないの。","ENG":"I've been calculating non-stop, but I don't have enough information.","TWN":"我也在持續計算中，但資訊不足。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"명색이 보물인데 날로 먹을 수는 없겠죠.","JPN":"お宝ですから、そう簡単には手に入らないですよね。","ENG":"Well, I guess treasure shouldn't be easy to find in the first place.","TWN":"既然是寶物，怎麼能不費吹灰之力就得到呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모처럼 휴양지에 왔으니 천천히 둘러보기라도 하자고요.","JPN":"せっかくリゾート地に来たんです。ゆっくり見て回りましょう。","ENG":"Since we're at a vacation destination, let's take our time looking around.","TWN":"難得來度假村，不如慢慢逛逛吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"파도에 휩쓸리는 작은 해조류들을 보며 문득 생각했다.","JPN":"波に揺られる海藻を見ていると、ふとこんなことが頭をよぎる。","ENG":"A thought randomly came to mind while I was looking at the seaweed that was swept up by the waves.","TWN":"看著被海浪捲走的小海藻，突然有些感觸。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"넘실거리는 파랑에 몸을 맡긴 우리도 저리 될 수 있었으리라.","JPN":"一歩間違えたら、私たちもあの海藻みたいになっていたかもしれない、と。","ENG":"We could've ended up like that, devoured by the waves.","TWN":"我們是不是也像那樣，任由著波濤起起伏伏。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"변덕 심한 바다를 셋이서 무사히 건넌 것만으로도 분명 작은 기적이었다고.","JPN":"この気まぐれな荒波を、3人で渡りきることができたのは奇跡だ。","ENG":"It was a small miracle that we crossed the fickle ocean without losing anyone.","TWN":"三個人平安渡過這片變幻莫測的大海，確實是個小奇蹟。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"먼저 가 있던 로저 씨가 등을 밀어주기라도 한 걸까?","JPN":"先に発ったロジャーさんが背中を押してくれたのだろうか？","ENG":"Perhaps Roger gave us a push toward this island to help us make it safe and sound.","TWN":"是先行一步的羅杰在背後推我們一把嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"파도 소리에 귀를 기울였다.","JPN":"波の音に耳を傾けた。","ENG":"I listened to the waves.","TWN":"傾聽著海浪的聲音。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"어쩐지 로저 씨의 목소리가 들린 것 같은 기분이었다.","JPN":"なんだかロジャーさんの声が聞こえるような気がする。","ENG":"It felt like I heard Roger's voice.","TWN":"總覺得好像有聽到羅杰的聲音。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"헛소리 마시죠, 마드모아젤.","JPN":"何を言っているんですか、マドモアゼル。","ENG":"Stop talking nonsense, mademoiselle.","TWN":"別再自言自語了，小姐。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"10년 같은 1시간이었습니다, 마드모아젤. 기다림의 미학이라는 말을 이곳에서 통감했지요.","JPN":"まるで10年のように感じられた1時間でしたよ。待つことの美学を身に沁みるほど感じさせられたひとときでした。","ENG":"The past hour felt like a decade, mademoiselle. I honed my patience here.","TWN":"過去的這幾小時如同幾十年一樣，小姐。我在這裡深刻地體會到了等待的美學。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"당신들을 후려치기만을 이곳에서 학수고대했습니다.","JPN":"ここでずっとあなたたちを殴り飛ばすことだけを、考えていたんです。","ENG":"I was waiting, fantasizing, about the moment I would ambush you.","TWN":"我是那麼期盼著在這裡狠狠地教訓你們一頓。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"오, 로저. 다시 보니 반갑네요.","JPN":"ロジャーさん。お久しぶりですね。元気でしたか？","ENG":"Oh, Roger. Good to see you again.","TWN":"呃，羅杰？再次見到你很高興？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"못 본 사이에 말투가 많이 험악해지셨네. 어디 안 좋은 일이라도 있으셨나?","JPN":"しばらく見ない間に、口ぶりが荒くなられましたね。何か悪いことでもあったんですか？","ENG":"You sound a lot more aggressive than before. Did something happen?","TWN":"好久不見，你的語氣變得很粗暴呢……是發生什麼不好的事情了嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제, 젠틀한 신사답게 대화로 해결하시죠, 로저.","JPN":"し、紳士らしく丁寧な会話を通じて解決を図りませんか？","ENG":"L-let's talk this out like gentlemen.","TWN":"請、請像紳士一樣用對話解決吧，羅杰。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"여긴 대체 어떻게 온 거예요?","JPN":"ここにはいったいどうやって？","ENG":"How did you even get here?","TWN":"你到底是怎麼到這裡的？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"당신의 재수감을 위해 경찰청으로부터 협력을 요청받았습니다.","JPN":"マドモアゼルたちを再拘束するよう、警察庁から協力要請があったんですよ。","ENG":"The police asked for my cooperation in order to reincarcerate you.","TWN":"警察局要求我配合他們將你重新收監。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"위치를 특정하는 데는 애먹었지만, 마드모아젤이 아니라면 보물을 쫓으면 그만.","JPN":"居場所の特定に手こずっていたところ、マドモアゼルではなく、お宝を追っていけばいいと気が付きました。","ENG":"I had trouble locating you, but I figured I could chase the treasure instead.","TWN":"雖然定位有些困難，但如果奔著寶藏去的話，就總能找到吧。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"세간에 공개된 암호와 프리 라이더라는 분들의 증언으로 섬을 특정했죠.","JPN":"なので世間に公表されている暗号と、フリーライダーという方々からの証言を照合して、この島を割り出したんです。","ENG":"I found the island based on the ciphertext that was revealed to the public and the testimony of some people called \\"Free Riders.\\"","TWN":"透過公開的密碼還有自稱自由騎士的證詞才確定到這裡。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"소신 발언.","JPN":"ちょっといいですか。","ENG":"Hot take.","TWN":"隨便一說。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레라면 그럴 시간에 반성문을 썼습니다.","JPN":"クレデレなら、そんなことをしないで反省文を書きました。","ENG":"Credere would have written an apology letter instead.","TWN":"如果是克蕾妲莉的話，現在已經在寫悔過書了。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"흐엑.","JPN":"ゲッ。","ENG":"Heek.","TWN":"呃。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"억지부리면 안 돼, 아저씨. 지금 유피는 술래잡기가 아닌 보물찾기 중이라구.","JPN":"そんなに意地を張らないでよね、おじさん。ユピは鬼ごっこじゃなくて、宝探し中なんだから。","ENG":"Don't try to bend the rules, mister. Yuppie is playing treasure hunt, not tag.","TWN":"不許耍賴，叔叔！現在悠菲在玩尋寶遊戲，不是捉迷藏！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님. 이건 술래잡기가 아니에요.","JPN":"室長、これは鬼ごっこではありません。","ENG":"Chief. This isn't tag.","TWN":"室長。這不是捉迷藏。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"로저 씨도 화난 건 알겠지만 진정하세요. 네?","JPN":"ロジャーさんも怒るお気持ちはわかりますが、少し落ち着きましょう？","ENG":"I understand that you're angry, but please calm down.","TWN":"羅杰，我知道你很生氣，但是請冷靜，可、可以嗎……？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"좋습니다. 전 젠틀한 신사인만큼 마지막 발언 정도는 들어드리죠.","JPN":"そうですね。真の紳士として最後の言い訳ぐらい聞いてあげるとしましょう。","ENG":"All right. I am a gentleman, and I will give you an opportunity to say your last piece.","TWN":"好吧，作為一名紳士，我會聽取你的最後發言。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"납득할 수밖에 없는 눈물겨운 사연이라도 있으셨습니까?","JPN":"何か私を納得させられる、涙ぐましい事情でも？","ENG":"Do you have some kind of tearjerker of a backstory?","TWN":"還有什麼讓人不得不接受的傷心故事嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"한 번만 봐줘라!","JPN":"今回だけ、見逃して！","ENG":"PLEASE, JUST LET THIS SLIDE!","TWN":"請你放過我吧！拜託——！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"싹 다 조져!!","JPN":"全員やっちまえ！！","ENG":"GET THEM ALL!!","TWN":"抓住她們！！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이런 젠장! 어떻게 하는 일마다 한 번을 못 넘어가?","JPN":"もうっ！　何で毎回こうなるの！？","ENG":"Damn it! Why does everything have to turn into a big deal?","TWN":"真是見鬼！為什麼每次求饒都沒有用！？"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피가 크레데레처럼 귀엽지 못한 탓입니다.","JPN":"ユピがクレデレみたいに可愛くないからです。","ENG":"It's because you are not as adorable as Credere.","TWN":"因為悠菲不如克蕾妲莉可愛。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"원래 남성은 귀여운 여성에게 간이고 쓸개고 내주는 법이니까요.","JPN":"男性は可愛い女に弱いものですよ。","ENG":"Men will do anything for cute women.","TWN":"畢竟男人總是會對可愛的女孩子掏心掏肺。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 지금껏 수많은 남심을 흔든 죄 많은 여자랍니다.","JPN":"何を隠そう、クレデレはこれまで数多の男性たちの心を射止めてきた、罪深き女なんです。","ENG":"No skeletons in this closet. Credere is guilty of charming many men.","TWN":"克蕾妲莉沒有祕密，克蕾妲莉其實是個罪孽深重的女人，至今為止已經撩動了無數男人的心。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"츄.","JPN":"ちゅっ。","ENG":"Chu.","TWN":"啾咪。"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"츄. 는 무슨 얼어죽을 츄! 너 때문에 이렇게 된 거잖아, 이 썩을 꼬맹아!!","JPN":"なにがちゅっだ！！　こうなったのも全部、あなたのせいなんだから！","ENG":"Chu, my butt! This is all because of you, you damn brat!","TWN":"啾！啾什麼啾！都怪你才會變成這樣，你這個該死的小鬼！！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"끝나면 각오해요, 크레데레!","JPN":"この件が落ち着いたら、お仕置きですよ！","ENG":"We're going to have a serious conversation after this, Credere!","TWN":"結束後你就等著吧，克蕾妲莉！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};